package com.example.oidc.service;

import com.example.oidc.config.ProviderSettings;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.Base64;

@Service
public class StateService {
    private static final String STATE_KEY = "OIDC_STATE";
    private static final String NONCE_KEY = "OIDC_NONCE";
    private final SecureRandom secureRandom = new SecureRandom();
    private final ProviderSettings providerSettings;

    public StateService(ProviderSettings providerSettings) {
        this.providerSettings = providerSettings;
    }

    public String generateState(HttpSession session) {
        String state = randomUrlSafe();
        session.setAttribute(STATE_KEY, state);
        return state;
    }

    public String generateNonce(HttpSession session) {
        String nonce = randomUrlSafe();
        session.setAttribute(NONCE_KEY, nonce);
        return nonce;
    }

    public boolean validateState(HttpSession session, String state) {
        Object stored = session.getAttribute(STATE_KEY);
        session.removeAttribute(STATE_KEY);
        return stored != null && stored.equals(state);
    }

    public boolean validateNonce(HttpSession session, String nonce) {
        Object stored = session.getAttribute(NONCE_KEY);
        session.removeAttribute(NONCE_KEY);
        return stored != null && stored.equals(nonce);
    }

    public String buildAuthorizationUrl(HttpSession session) {
        String state = generateState(session);
        String nonce = generateNonce(session);
        return providerSettings.getAuthorizationUri()
                + "?response_type=code"
                + "&client_id=" + url(providerSettings.getClientId())
                + "&redirect_uri=" + url(providerSettings.getRedirectUri())
                + "&scope=" + url(providerSettings.getScope())
                + "&state=" + url(state)
                + "&nonce=" + url(nonce);
    }

    private String randomUrlSafe() {
        byte[] bytes = new byte[24];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String url(String value) {
        return java.net.URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}

package com.example.oidc.service;

import com.example.oidc.config.ProviderSettings;
import com.example.oidc.model.TokenResponse;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

@Service
public class TokenService {
    private final RestTemplate restTemplate;
    private final ProviderSettings providerSettings;

    public TokenService(RestTemplate restTemplate, ProviderSettings providerSettings) {
        this.restTemplate = restTemplate;
        this.providerSettings = providerSettings;
    }

    public TokenResponse exchangeAuthorizationCode(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));
        headers.set(HttpHeaders.AUTHORIZATION, basicAuth());

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", code);
        body.add("redirect_uri", providerSettings.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);
        ResponseEntity<TokenResponse> response = restTemplate.exchange(
                providerSettings.getTokenUri(),
                HttpMethod.POST,
                request,
                TokenResponse.class
        );
        return response.getBody();
    }

    public java.util.Map<String, Object> fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);
        ResponseEntity<java.util.Map> response = restTemplate.exchange(
                providerSettings.getUserInfoUri(),
                HttpMethod.GET,
                request,
                java.util.Map.class
        );
        return response.getBody();
    }

    private String basicAuth() {
        String value = providerSettings.getClientId() + ":" + providerSettings.getClientSecret();
        return "Basic " + Base64.getEncoder().encodeToString(value.getBytes(StandardCharsets.UTF_8));
    }
}

package com.example.oidc.service;

import com.example.oidc.config.ProviderSettings;
import com.example.oidc.model.TokenResponse;
import com.example.oidc.model.UserSession;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;
import java.util.Map;
import java.util.UUID;

@Service
public class OidcAuthenticationService {
    public static final String USER_SESSION_KEY = "OIDC_USER_SESSION";

    private final TokenService tokenService;
    private final StateService stateService;
    private final ProviderSettings providerSettings;
    private final ObjectMapper objectMapper = new ObjectMapper();

    public OidcAuthenticationService(TokenService tokenService, StateService stateService, ProviderSettings providerSettings) {
        this.tokenService = tokenService;
        this.stateService = stateService;
        this.providerSettings = providerSettings;
    }

    public UserSession authenticate(String code, String state, HttpSession httpSession) {
        if (!stateService.validateState(httpSession, state)) {
            throw new IllegalArgumentException("Invalid state");
        }

        TokenResponse tokenResponse = tokenService.exchangeAuthorizationCode(code);
        if (tokenResponse == null || tokenResponse.getIdToken() == null) {
            throw new IllegalStateException("Missing token response or id_token");
        }

        Map<String, Object> claims = parseIdTokenClaims(tokenResponse.getIdToken());
        validateClaims(claims, httpSession);

        Map<String, Object> userInfo = null;
        if (tokenResponse.getAccessToken() != null && providerSettings.getUserInfoUri() != null && !providerSettings.getUserInfoUri().isBlank()) {
            userInfo = tokenService.fetchUserInfo(tokenResponse.getAccessToken());
        }

        UserSession userSession = new UserSession();
        userSession.setSessionId(UUID.randomUUID().toString());
        userSession.setSubject(stringClaim(claims, "sub"));
        userSession.setUsername(firstNonBlank(
                stringClaim(claims, "preferred_username"),
                userInfo != null ? asString(userInfo.get("preferred_username")) : null,
                stringClaim(claims, "name"),
                userInfo != null ? asString(userInfo.get("name")) : null,
                stringClaim(claims, "sub")
        ));
        userSession.setEmail(firstNonBlank(
                stringClaim(claims, "email"),
                userInfo != null ? asString(userInfo.get("email")) : null
        ));
        userSession.setAccessToken(tokenResponse.getAccessToken());
        userSession.setRefreshToken(tokenResponse.getRefreshToken());
        userSession.setIdToken(tokenResponse.getIdToken());
        userSession.setExpiresAt(Instant.now().plusSeconds(tokenResponse.getExpiresIn() != null ? tokenResponse.getExpiresIn() : 3600));
        userSession.setClaims(claims);
        userSession.setUserInfo(userInfo);

        httpSession.setAttribute(USER_SESSION_KEY, userSession);
        return userSession;
    }

    public UserSession currentUser(HttpSession session) {
        Object value = session.getAttribute(USER_SESSION_KEY);
        return value instanceof UserSession ? (UserSession) value : null;
    }

    public void logout(HttpSession session) {
        session.removeAttribute(USER_SESSION_KEY);
        session.invalidate();
    }

    private Map<String, Object> parseIdTokenClaims(String idToken) {
        try {
            String[] parts = idToken.split("\\.");
            if (parts.length < 2) {
                throw new IllegalArgumentException("Invalid JWT");
            }
            byte[] payload = Base64.getUrlDecoder().decode(parts[1]);
            return objectMapper.readValue(new String(payload, StandardCharsets.UTF_8), new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse id_token", e);
        }
    }

    private void validateClaims(Map<String, Object> claims, HttpSession session) {
        String issuer = stringClaim(claims, "iss");
        String audience = audience(claims.get("aud"));
        String nonce = stringClaim(claims, "nonce");
        Long exp = longClaim(claims, "exp");

        if (providerSettings.getIssuer() != null && !providerSettings.getIssuer().isBlank()) {
            if (!providerSettings.getIssuer().equals(issuer)) {
                throw new IllegalArgumentException("Invalid issuer");
            }
        }

        if (audience == null || !audience.contains(providerSettings.getClientId())) {
            throw new IllegalArgumentException("Invalid audience");
        }

        if (!stateService.validateNonce(session, nonce)) {
            throw new IllegalArgumentException("Invalid nonce");
        }

        if (exp != null && Instant.ofEpochSecond(exp).isBefore(Instant.now())) {
            throw new IllegalArgumentException("Expired id_token");
        }
    }

    private String audience(Object aud) {
        if (aud instanceof String) {
            return (String) aud;
        }
        if (aud instanceof java.util.Collection<?> collection) {
            StringBuilder sb = new StringBuilder();
            for (Object item : collection) {
                if (sb.length() > 0) sb.append(' ');
                sb.append(String.valueOf(item));
            }
            return sb.toString();
        }
        return null;
    }

    private String stringClaim(Map<String, Object> claims, String key) {
        return asString(claims.get(key));
    }

    private Long longClaim(Map<String, Object> claims, String key) {
        Object value = claims.get(key);
        if (value instanceof Number n) {
            return n.longValue();
        }
        if (value instanceof String s) {
            return Long.parseLong(s);
        }
        return null;
    }

    private String asString(Object value) {
        return value == null ? null : String.valueOf(value);
    }

    private String firstNonBlank(String... values) {
        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }
        return null;
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.OidcAuthenticationService;
import com.example.oidc.service.StateService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class AuthController {
    private final StateService stateService;
    private final OidcAuthenticationService authenticationService;

    public AuthController(StateService stateService, OidcAuthenticationService authenticationService) {
        this.stateService = stateService;
        this.authenticationService = authenticationService;
    }

    @GetMapping("/auth/login")
    public Map<String, String> login(HttpSession session) {
        return Map.of("authorizationUrl", stateService.buildAuthorizationUrl(session));
    }

    @GetMapping(value = "/auth/callback", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> callback(String code, String state, HttpSession session) {
        UserSession userSession = authenticationService.authenticate(code, state, session);
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", true);
        response.put("sessionId", userSession.getSessionId());
        response.put("subject", userSession.getSubject());
        response.put("username", userSession.getUsername());
        response.put("email", userSession.getEmail());
        response.put("claims", userSession.getClaims());
        response.put("userInfo", userSession.getUserInfo());
        return response;
    }

    @GetMapping("/auth/me")
    public Map<String, Object> me(HttpSession session) {
        UserSession userSession = authenticationService.currentUser(session);
        if (userSession == null) {
            return Map.of("authenticated", false);
        }
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", true);
        response.put("sessionId", userSession.getSessionId());
        response.put("subject", userSession.getSubject());
        response.put("username", userSession.getUsername());
        response.put("email", userSession.getEmail());
        response.put("expiresAt", userSession.getExpiresAt());
        response.put("claims", userSession.getClaims());
        response.put("userInfo", userSession.getUserInfo());
        return response;
    }

    @PostMapping("/auth/logout")
    public Map<String, Object> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            authenticationService.logout(session);
        }
        return Map.of("loggedOut", true);
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.OidcAuthenticationService;
import jakarta.servlet.http.HttpSession;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.Map;

@RestController
public class HomeController {
    private final OidcAuthenticationService authenticationService;

    public HomeController(OidcAuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    @GetMapping("/")
    public Map<String, Object> home(HttpSession session) {
        UserSession userSession = authenticationService.currentUser(session);
        if (userSession == null) {
            return Map.of(
                    "message", "Welcome",
                    "authenticated", false,
                    "login", "/auth/login"
            );
        }
        return Map.of(
                "message", "Welcome " + userSession.getUsername(),
                "authenticated", true,
                "subject", userSession.getSubject(),
                "email", userSession.getEmail()
        );
    }
}

